# BrainstormPanel JSON Schema 设计

## 1. JSON Schema 定义

### 1.1 BrainstormPanel 输入模型 (InputSchema.json)
```json
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://symphony.openclaw/schemas/BrainstormPanelInput.json",
  "title": "BrainstormPanel Input",
  "description": "头脑风暴面板输入参数",
  "type": "object",
  "properties": {
    "session_id": {
      "type": "string",
      "description": "会话唯一标识符",
      "minLength": 1,
      "maxLength": 64
    },
    "topic": {
      "type": "string",
      "description": "头脑风暴主题",
      "minLength": 1,
      "maxLength": 200
    },
    "constraints": {
      "type": "array",
      "description": "约束条件列表",
      "items": {
        "type": "string",
        "maxLength": 100
      },
      "default": []
    },
    "max_ideas": {
      "type": "integer",
      "description": "最大生成想法数量",
      "minimum": 1,
      "maximum": 50,
      "default": 10
    },
    "thinking_style": {
      "type": "string",
      "description": "思考风格",
      "enum": ["divergent", "convergent", "lateral", "critical"],
      "default": "divergent"
    },
    "depth": {
      "type": "integer",
      "description": "思考深度级别",
      "minimum": 1,
      "maximum": 3,
      "default": 2
    },
    "context": {
      "type": "object",
      "description": "上下文信息",
      "properties": {
        "industry": {
          "type": "string",
          "description": "所属行业"
        },
        "audience": {
          "type": "string",
          "description": "目标受众"
        },
        "budget_range": {
          "type": "string",
          "description": "预算范围"
        },
        "timeline": {
          "type": "string",
          "description": "时间线要求"
        }
      },
      "additionalProperties": false
    }
  },
  "required": ["session_id", "topic"],
  "additionalProperties": false
}
```

### 1.2 BrainstormPanel 输出模型 (OutputSchema.json)
```json
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://symphony.openclaw/schemas/BrainstormPanelOutput.json",
  "title": "BrainstormPanel Output",
  "description": "头脑风暴面板输出结果",
  "type": "object",
  "properties": {
    "session_id": {
      "type": "string",
      "description": "会话唯一标识符"
    },
    "topic": {
      "type": "string",
      "description": "头脑风暴主题"
    },
    "generated_at": {
      "type": "string",
      "format": "date-time",
      "description": "生成时间戳"
    },
    "ideas": {
      "type": "array",
      "description": "生成的想法列表",
      "items": {
        "type": "object",
        "properties": {
          "id": {
            "type": "string",
            "description": "想法唯一ID"
          },
          "title": {
            "type": "string",
            "description": "想法标题",
            "maxLength": 100
          },
          "description": {
            "type": "string",
            "description": "详细描述",
            "maxLength": 500
          },
          "category": {
            "type": "string",
            "description": "分类标签",
            "enum": ["innovative", "practical", "risky", "low_cost", "high_impact"]
          },
          "feasibility_score": {
            "type": "number",
            "description": "可行性评分 (0-10)",
            "minimum": 0,
            "maximum": 10
          },
          "impact_score": {
            "type": "number",
            "description": "影响力评分 (0-10)",
            "minimum": 0,
            "maximum": 10
          },
          "key_points": {
            "type": "array",
            "description": "关键要点",
            "items": {
              "type": "string",
              "maxLength": 150
            }
          },
          "risks": {
            "type": "array",
            "description": "潜在风险",
            "items": {
              "type": "string",
              "maxLength": 150
            }
          }
        },
        "required": ["id", "title", "description", "category"],
        "additionalProperties": false
      }
    },
    "summary": {
      "type": "object",
      "description": "分析总结",
      "properties": {
        "total_ideas": {
          "type": "integer",
          "description": "想法总数"
        },
        "category_distribution": {
          "type": "object",
          "description": "分类分布",
          "additionalProperties": {
            "type": "integer",
            "minimum": 0
          }
        },
        "avg_feasibility": {
          "type": "number",
          "description": "平均可行性评分"
        },
        "avg_impact": {
          "type": "number",
          "description": "平均影响力评分"
        },
        "recommendations": {
          "type": "array",
          "description": "推荐想法ID列表",
          "items": {
            "type": "string"
          }
        }
      },
      "required": ["total_ideas"],
      "additionalProperties": false
    },
    "metadata": {
      "type": "object",
      "description": "元数据",
      "properties": {
        "thinking_style_used": {
          "type": "string",
          "description": "使用的思考风格"
        },
        "depth_level": {
          "type": "integer",
          "description": "思考深度级别"
        },
        "processing_time_ms": {
          "type": "integer",
          "description": "处理时间（毫秒）"
        }
      },
      "additionalProperties": false
    }
  },
  "required": ["session_id", "topic", "ideas", "summary"],
  "additionalProperties": false
}
```

